mapper.select:
SELECT t.task_id, t.email, t.owner_type, t.category_id, t.title, t.content, t.status, t.start_at, t.end_at, t.client_company, t.budget, t.paid_at, t.auto_registered, t.auto_registered_source FROM task t INNER JOIN category c ON c.category_id = t.category_id WHERE t.email = #{email} AND t.owner_type = #{ownerType} AND c.email = #{email} AND c.owner_type = #{ownerType} AND t.start_at < DATE_ADD( STR_TO_DATE(CONCAT(#{year}, '-', LPAD(#{month}, 2, '0'), '-01'), '%Y-%m-%d'), INTERVAL 1 MONTH ) AND t.end_at >= STR_TO_DATE(CONCAT(#{year}, '-', LPAD(#{month}, 2, '0'), '-01'), '%Y-%m-%d')
AND t.category_id = #{categoryId}
ORDER BY t.start_at ASC, t.task_id ASC

mapper.update:
UPDATE task t
INNER JOIN category c
    ON c.category_id = t.category_id
SET
    t.category_id = #{categoryId},
    t.title = #{title},
    t.content = #{content},

    t.status = #{status},

    t.start_at = #{startAt},
    t.end_at = #{endAt},
    t.client_company = #{clientCompany},
    t.budget = #{budget},
    t.paid_at = #{paidAt},
    t.auto_registered = #{autoRegistered},
    t.auto_registered_source = #{autoRegisteredSource}
WHERE t.task_id = #{taskId}
  AND t.email = #{email}
  AND t.owner_type = #{ownerType}
  AND c.email = #{email}
  AND c.owner_type = #{ownerType}

mapper.delete:
DELETE t
FROM task t
INNER JOIN category c
    ON c.category_id = t.category_id
WHERE t.task_id = #{taskId}
  AND t.email = #{email}
  AND t.owner_type = #{ownerType}
  AND c.email = #{email}
  AND c.owner_type = #{ownerType}

DELETE FROM task
WHERE email = #{email}
  AND owner_type = #{ownerType}

mapper.update:
UPDATE task t
INNER JOIN category source_category
    ON source_category.category_id = t.category_id
INNER JOIN category target_category
    ON target_category.category_id = #{moveToCategoryId}
SET t.category_id = #{moveToCategoryId}
WHERE t.category_id = #{categoryId}
  AND t.email = #{email}
  AND t.owner_type = #{ownerType}
  AND source_category.email = #{email}
  AND source_category.owner_type = #{ownerType}
  AND target_category.email = #{email}
  AND target_category.owner_type = #{ownerType}
